import create from 'zustand';

/**
 * Zustand store for managing performance metrics and project standards.
 */
const useStore = create((set) => ({
    metrics: [],
    standards: {},
    addMetric: (metric) => set((state) => ({
        metrics: [...state.metrics, metric],
    })),
    updateStandards: (newStandards) => set({ standards: newStandards }),
}));

/**
 * Fetch performance metrics from the API.
 * @returns {Promise<Array>} The list of performance metrics.
 */
async function fetchPerformanceMetrics() {
    try {
        const response = await fetch('http://localhost:3001/metrics');
        if (!response.ok) throw new Error('Failed to fetch metrics');
        return await response.json();
    } catch (error) {
        console.error('Error fetching performance metrics:', error);
        return [];
    }
}

/**
 * Update project standards based on performance metrics.
 * @param {Object} standards The current project standards.
 * @param {Array} metrics The performance metrics to evaluate.
 * @returns {Object} The updated project standards.
 */
function evaluateStandards(standards, metrics) {
    const updatedStandards = { ...standards };
    
    if (metrics.length > 0) {
        const averagePerformance = metrics.reduce((sum, metric) => sum + metric.value, 0) / metrics.length;

        if (averagePerformance < 50) {
            updatedStandards.quality = 'low';
            updatedStandards.recommendations = 'Increase testing coverage';
        } else if (averagePerformance < 75) {
            updatedStandards.quality = 'medium';
            updatedStandards.recommendations = 'Improve code reviews';
        } else {
            updatedStandards.quality = 'high';
            updatedStandards.recommendations = 'Keep up the good work';
        }
    }
    
    return updatedStandards;
}

/**
 * Persist updated standards to the API.
 * @param {Object} standards The updated project standards.
 * @returns {Promise<void>}
 */
async function persistStandards(standards) {
    try {
        const response = await fetch('http://localhost:3001/standards', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(standards),
        });
        if (!response.ok) throw new Error('Failed to persist standards');
    } catch (error) {
        console.error('Error persisting standards:', error);
    }
}

/**
 * Self-evolving canon feature that fetches metrics and updates standards.
 * @returns {Promise<void>}
 */
export async function selfEvolvingCanon() {
    const metrics = await fetchPerformanceMetrics();
    const currentStandards = useStore.getState().standards;
    const updatedStandards = evaluateStandards(currentStandards, metrics);
    
    useStore.getState().updateStandards(updatedStandards);
    await persistStandards(updatedStandards);
}

/**
 * Get current project standards.
 * @returns {Object} The current project standards.
 */
export function getCurrentStandards() {
    return useStore.getState().standards;
}

/**
 * Add a performance metric.
 * @param {Object} metric The performance metric to add.
 */
export function addPerformanceMetric(metric) {
    useStore.getState().addMetric(metric);
}

export { useStore };